const root = $input.first().json;
const payload = root.body ?? root;
const data = payload.data ?? payload;
const messageObject = data.message ?? data;
const fromMe = Boolean(data.fromMe ?? data.key?.fromMe ?? messageObject.fromMe ?? messageObject.key?.fromMe);

// Ignorer les messages envoyés par le bot lui-même pour éviter une boucle.
if (fromMe) {
  return [];
}

const messageType = String(data.type ?? messageObject.type ?? payload.type ?? 'text').toLowerCase();
const hasMedia = Boolean(
  data.isMedia ??
  messageObject.isMedia ??
  data.mimetype ??
  messageObject.mimetype ??
  ['image', 'document', 'video', 'audio', 'ptt', 'sticker'].includes(messageType)
);
const text = data.body ?? data.text?.body ?? data.content ?? data.conversation ?? messageObject.body ?? '';

if (!String(text ?? '').trim()) {
  data.body = hasMedia ? '[MEDIA_SANS_TEXTE]' : '[MESSAGE_VIDE]';
}

return [{ json: root }];

const root = $input.first().json;
const payload = root.body ?? root;
const data = payload.data ?? payload;
const messageObject = data.message ?? data;

const headers = root.headers ?? {};
const idempotencyKey =
  headers['x-openwa-idempotency-key'] ??
  headers['X-OpenWA-Idempotency-Key'] ??
  '';
const headerMatch = String(idempotencyKey)
  .match(/^msg_([^_]+)_(?:true|false)_([^_]+)_/);
const sessionFromHeader = headerMatch?.[1];
const chatFromHeader = headerMatch?.[2];

const chatId =
  data.from ??
  data.chatId ??
  data.chat_id ??
  data.key?.remoteJid ??
  data.remoteJid ??
  data.sender?.id ??
  messageObject.from ??
  messageObject.chatId ??
  messageObject.key?.remoteJid ??
  payload.from ??
  payload.chatId ??
  payload.messages?.[0]?.from ??
  payload.messages?.[0]?.key?.remoteJid ??
  chatFromHeader;

const messageText =
  data.body ??
  data.text?.body ??
  data.content ??
  data.conversation ??
  data.extendedTextMessage?.text ??
  messageObject.body ??
  messageObject.text?.body ??
  messageObject.conversation ??
  messageObject.extendedTextMessage?.text ??
  payload.message?.body ??
  payload.messages?.[0]?.text?.body ??
  payload.messages?.[0]?.message?.conversation ??
  payload.messages?.[0]?.message?.extendedTextMessage?.text ??
  '';

const sessionId =
  payload.sessionId ??
  payload.session_id ??
  data.sessionId ??
  data.session_id ??
  sessionFromHeader;

const timestamp =
  data.timestamp ??
  messageObject.timestamp ??
  payload.timestamp ??
  Date.now();

if (!chatId) {
  throw new Error('Chat ID OpenWA introuvable. Vérifiez le JSON de sortie du Webhook.');
}
if (!String(messageText).trim()) {
  throw new Error('Texte du message OpenWA introuvable dans le Webhook');
}
if (!sessionId) {
  throw new Error('Session ID OpenWA introuvable dans le Webhook');
}

return [{
  json: {
    chatInput: String(messageText).trim(),
    messageText: String(messageText).trim(),
    chatId: String(chatId).trim(),
    userId: String(chatId).trim(),
    userName: data.sender?.pushname ?? data.notifyName ?? 'Client',
    sessionId: String(sessionId).trim(),
    timestamp
  }
}];

const source = $('Extraire message OpenWA').first().json;
const result = $input.first().json;
const turn = result?.data ?? {};
return [{
  json: {
    ...source,
    turnResult: result,
    catalogueResult: { success: result?.success, data: { products: turn.products ?? [] } },
    catalogueJson: JSON.stringify({ success: result?.success, data: { products: turn.products ?? [] } }),
    selectedProduct: turn.selected_product ?? null,
    directResponse: turn.direct_response ?? null,
    handled: Boolean(turn.handled)
  }
}];

const agent = $input.first().json;
const source = $('Extraire message OpenWA').first().json;
let answer = agent.output ?? agent.response ?? agent.text;

if (!answer || typeof answer !== 'string' || !answer.trim()) {
  answer = 'Je rencontre un problème technique temporaire. Merci de réessayer dans quelques instants.';
}

answer = answer
  .replace(/<think>[\s\S]*?<\/think>/gi, '')
  .replace(/\*\*/g, '')
  .trim();

const leaksInternalContent =
  /(^|\n)\s*(we need|we have to|let's think|the user|i need to|system message)/i.test(answer) ||
  /\"name\"\s*:\s*\"commerce_api\"/i.test(answer) ||
  /\"arguments\"\s*:/i.test(answer);

if (leaksInternalContent || !answer) {
  answer = 'Je rencontre un problème technique temporaire pour traiter cette demande. Merci de réessayer dans quelques instants.';
}

return [{
  json: {
    chatId: source.chatId,
    sessionId: source.sessionId,
    message: answer
  }
}];

return [{
  json: {
    output: 'Un instant, je rencontre un souci technique. Merci de réessayer dans quelques instants ou demandez un conseiller.',
    technicalFallback: true
  }
}];
